/**
 * Subscription Module Types
 *
 * Type definitions for the Subscription module including:
 * - Plan entity types
 * - Subscription entity types
 * - Invoice entity types
 * - Feature gating types
 * - Event payloads
 * - Query filters
 *
 * @module modules/_core/subscription/types
 *
 * @example
 * ```typescript
 * import type {
 *   Plan,
 *   Subscription,
 *   CreateSubscriptionRequest,
 *   FeatureCheckResult,
 * } from '@/modules/_core/subscription/subscription.types';
 *
 * async function checkFeature(orgId: string, feature: string): Promise<FeatureCheckResult> { ... }
 * ```
 */

import type { SubscriptionStatus, InvoiceStatus, PaymentMethod } from '@prisma/client';

// -----------------------------------------------------------------------------
// Plan Types
// -----------------------------------------------------------------------------

/**
 * Plan tier enumeration
 */
export type PlanTier = 'free' | 'starter' | 'professional' | 'business' | 'enterprise';

/**
 * Plan entity from Prisma
 */
export interface Plan {
  /** Unique identifier (CUID) */
  id: string;
  /** Plan name (unique, lowercase) */
  name: string;
  /** Display name for UI */
  displayName: string;
  /** Plan description */
  description: string | null;
  /** Monthly price in TRY */
  monthlyPrice: number;
  /** Annual price in TRY */
  annualPrice: number;
  /** Currency code */
  currency: string;
  /** List of included features */
  features: PlanFeatures;
  /** Resource and usage limits */
  limits: PlanLimits;
  /** Whether plan is active and available */
  isActive: boolean;
  /** Sort order for display */
  sortOrder: number;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
}

/**
 * Plan features structure
 */
export interface PlanFeatures {
  /** Core features */
  core?: CoreFeatures;
  /** Order-related features */
  orders?: OrderFeatures;
  /** AI-powered features */
  ai?: AIFeatures;
  /** Advanced features */
  advanced?: AdvancedFeatures;
}

/**
 * Core feature flags
 */
export interface CoreFeatures {
  /** Digital menu */
  digitalMenu?: boolean;
  /** QR code generation */
  qrCodeGeneration?: boolean;
  /** Basic analytics */
  basicAnalytics?: boolean;
  /** E-Menum watermark (free only) */
  watermark?: boolean;
  /** Custom domain */
  customDomain?: boolean;
  /** White label */
  whiteLabel?: boolean;
}

/**
 * Order feature flags
 */
export interface OrderFeatures {
  /** Order receiving */
  orderReceiving?: boolean;
  /** Kitchen display system */
  kitchenDisplay?: boolean;
  /** Waiter app */
  waiterApp?: boolean;
  /** Table management */
  tableManagement?: boolean;
  /** Service requests */
  serviceRequests?: boolean;
}

/**
 * AI feature flags
 */
export interface AIFeatures {
  /** AI content generation */
  contentGeneration?: boolean;
  /** AI image generation */
  imageGeneration?: boolean;
  /** AI translation */
  translation?: boolean;
  /** AI insights */
  insights?: boolean;
  /** AI forecasting */
  forecasting?: boolean;
  /** Natural language queries */
  naturalQuery?: boolean;
}

/**
 * Advanced feature flags
 */
export interface AdvancedFeatures {
  /** Multi-branch support */
  multiBranch?: boolean;
  /** Central menu management */
  centralMenuManagement?: boolean;
  /** Marketing campaigns */
  campaigns?: boolean;
  /** Loyalty program */
  loyaltyProgram?: boolean;
  /** API access */
  apiAccess?: boolean;
  /** Webhooks */
  webhooks?: boolean;
  /** Custom integrations */
  customIntegrations?: boolean;
  /** Priority support */
  prioritySupport?: boolean;
  /** Dedicated account manager */
  dedicatedAccount?: boolean;
  /** SLA guarantee */
  slaGuarantee?: boolean;
}

/**
 * Plan resource and usage limits
 */
export interface PlanLimits {
  /** Resource limits */
  resources?: ResourceLimits;
  /** Monthly limits */
  monthly?: MonthlyLimits;
}

/**
 * Resource limits
 */
export interface ResourceLimits {
  /** Maximum menus */
  menus?: number;
  /** Maximum categories per menu */
  categoriesPerMenu?: number;
  /** Maximum products */
  products?: number;
  /** Maximum QR codes */
  qrCodes?: number;
  /** Maximum users */
  users?: number;
  /** Maximum branches */
  branches?: number;
  /** Maximum storage in MB */
  storageMB?: number;
}

/**
 * Monthly limits
 */
export interface MonthlyLimits {
  /** QR scans per month */
  qrScans?: number;
  /** Orders per month */
  orders?: number;
  /** AI credits per month */
  aiCredits?: number;
  /** API requests per month */
  apiRequests?: number;
  /** Report exports per month */
  exports?: number;
}

// -----------------------------------------------------------------------------
// Subscription Types
// -----------------------------------------------------------------------------

/**
 * Subscription entity from Prisma
 */
export interface Subscription {
  /** Unique identifier (CUID) */
  id: string;
  /** Organization ID */
  organizationId: string;
  /** Plan ID */
  planId: string;
  /** Current subscription status */
  status: SubscriptionStatus;
  /** Current billing period start */
  currentPeriodStart: Date;
  /** Current billing period end */
  currentPeriodEnd: Date;
  /** Whether to cancel at period end */
  cancelAtPeriodEnd: boolean;
  /** When subscription was cancelled */
  cancelledAt: Date | null;
  /** Trial start date */
  trialStart: Date | null;
  /** Trial end date */
  trialEnd: Date | null;
  /** Payment method */
  paymentMethod: PaymentMethod | null;
  /** Last successful payment date */
  lastPaymentAt: Date | null;
  /** Next payment date */
  nextPaymentAt: Date | null;
  /** Additional metadata */
  metadata: SubscriptionMetadata;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
}

/**
 * Subscription with related data
 */
export interface SubscriptionWithRelations extends Subscription {
  /** Associated plan */
  plan: Plan;
  /** Associated organization */
  organization?: {
    id: string;
    name: string;
    slug: string;
  };
  /** Recent invoices */
  invoices?: Invoice[];
}

/**
 * Subscription metadata
 */
export interface SubscriptionMetadata {
  /** Previous plan ID (for plan change history) */
  previousPlanId?: string;
  /** Cancellation reason */
  cancellationReason?: string;
  /** Upgrade/downgrade history */
  planHistory?: PlanChangeRecord[];
  /** Custom notes */
  notes?: string;
  /** External payment provider reference */
  externalReference?: string;
}

/**
 * Plan change history record
 */
export interface PlanChangeRecord {
  /** Previous plan ID */
  fromPlanId: string;
  /** New plan ID */
  toPlanId: string;
  /** Change date */
  changedAt: string;
  /** Change reason */
  reason?: string;
  /** User who made the change */
  changedBy?: string;
}

// -----------------------------------------------------------------------------
// Invoice Types
// -----------------------------------------------------------------------------

/**
 * Invoice entity from Prisma
 */
export interface Invoice {
  /** Unique identifier (CUID) */
  id: string;
  /** Subscription ID */
  subscriptionId: string;
  /** Invoice number */
  invoiceNumber: string;
  /** Invoice status */
  status: InvoiceStatus;
  /** Subtotal amount */
  subtotal: number;
  /** Tax amount */
  taxAmount: number;
  /** Total amount */
  totalAmount: number;
  /** Currency code */
  currency: string;
  /** Due date */
  dueDate: Date;
  /** Payment date */
  paidAt: Date | null;
  /** Payment method used */
  paymentMethod: PaymentMethod | null;
  /** Invoice description */
  description: string | null;
  /** Line items */
  lineItems: InvoiceLineItem[];
  /** Additional metadata */
  metadata: InvoiceMetadata;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
}

/**
 * Invoice line item
 */
export interface InvoiceLineItem {
  /** Line item description */
  description: string;
  /** Quantity */
  quantity: number;
  /** Unit price */
  unitPrice: number;
  /** Total price */
  totalPrice: number;
  /** Item type */
  type: 'subscription' | 'addon' | 'credit' | 'discount';
  /** Period start (for subscriptions) */
  periodStart?: string;
  /** Period end (for subscriptions) */
  periodEnd?: string;
}

/**
 * Invoice metadata
 */
export interface InvoiceMetadata {
  /** Organization name */
  organizationName?: string;
  /** Billing address */
  billingAddress?: BillingAddress;
  /** Tax ID */
  taxId?: string;
  /** External payment reference */
  paymentReference?: string;
  /** Refund reference (if refunded) */
  refundReference?: string;
}

/**
 * Billing address
 */
export interface BillingAddress {
  /** Street address */
  street: string;
  /** City */
  city: string;
  /** State/Province */
  state?: string;
  /** Postal code */
  postalCode: string;
  /** Country code */
  country: string;
}

// -----------------------------------------------------------------------------
// Feature Gating Types
// -----------------------------------------------------------------------------

/**
 * Feature check result
 */
export interface FeatureCheckResult {
  /** Whether the feature is available */
  allowed: boolean;
  /** Current plan tier */
  currentTier: PlanTier;
  /** Required tier for this feature */
  requiredTier?: PlanTier;
  /** Human-readable message */
  message?: string;
}

/**
 * Limit check result
 */
export interface LimitCheckResult {
  /** Whether within limits */
  allowed: boolean;
  /** Current usage */
  current: number;
  /** Maximum allowed */
  limit: number;
  /** Usage percentage (0-100) */
  usagePercent: number;
  /** Human-readable message */
  message?: string;
}

/**
 * Usage summary for an organization
 */
export interface UsageSummary {
  /** Organization ID */
  organizationId: string;
  /** Current plan */
  plan: {
    id: string;
    name: string;
    displayName: string;
  };
  /** Resource usage */
  resources: {
    menus: UsageItem;
    products: UsageItem;
    qrCodes: UsageItem;
    users: UsageItem;
    branches: UsageItem;
    storageMB: UsageItem;
  };
  /** Monthly usage (resets on billing date) */
  monthly: {
    qrScans: UsageItem;
    orders: UsageItem;
    aiCredits: UsageItem;
    apiRequests: UsageItem;
    exports: UsageItem;
  };
  /** Billing period */
  billingPeriod: {
    start: Date;
    end: Date;
    daysRemaining: number;
  };
}

/**
 * Individual usage item
 */
export interface UsageItem {
  /** Current usage */
  current: number;
  /** Maximum limit (-1 for unlimited) */
  limit: number;
  /** Usage percentage */
  percent: number;
  /** Whether at limit */
  atLimit: boolean;
  /** Whether over soft limit (80%) */
  nearLimit: boolean;
}

// -----------------------------------------------------------------------------
// Request/Response Types
// -----------------------------------------------------------------------------

/**
 * Create subscription request
 */
export interface CreateSubscriptionRequest {
  /** Organization ID */
  organizationId: string;
  /** Plan ID */
  planId: string;
  /** Start with trial */
  startTrial?: boolean;
  /** Payment method */
  paymentMethod?: PaymentMethod;
  /** Initial metadata */
  metadata?: Partial<SubscriptionMetadata>;
}

/**
 * Create subscription response
 */
export interface CreateSubscriptionResponse {
  /** Created subscription */
  subscription: SubscriptionWithRelations;
  /** Success message */
  message: string;
}

/**
 * Update subscription request
 */
export interface UpdateSubscriptionRequest {
  /** New payment method */
  paymentMethod?: PaymentMethod;
  /** Cancel at period end */
  cancelAtPeriodEnd?: boolean;
  /** Additional metadata */
  metadata?: Partial<SubscriptionMetadata>;
}

/**
 * Update subscription response
 */
export interface UpdateSubscriptionResponse {
  /** Updated subscription */
  subscription: Subscription;
  /** Success message */
  message: string;
}

/**
 * Change plan request
 */
export interface ChangePlanRequest {
  /** New plan ID */
  planId: string;
  /** Apply immediately or at period end */
  immediate?: boolean;
  /** Change reason */
  reason?: string;
}

/**
 * Change plan response
 */
export interface ChangePlanResponse {
  /** Updated subscription */
  subscription: SubscriptionWithRelations;
  /** Previous plan */
  previousPlan: Plan;
  /** New plan */
  newPlan: Plan;
  /** Prorated amount (if immediate) */
  proratedAmount?: number;
  /** Success message */
  message: string;
}

/**
 * Cancel subscription request
 */
export interface CancelSubscriptionRequest {
  /** Cancel immediately or at period end */
  immediate?: boolean;
  /** Cancellation reason */
  reason?: string;
}

/**
 * Cancel subscription response
 */
export interface CancelSubscriptionResponse {
  /** Updated subscription */
  subscription: Subscription;
  /** When access ends */
  accessEndsAt: Date;
  /** Success message */
  message: string;
}

/**
 * Reactivate subscription request
 */
export interface ReactivateSubscriptionRequest {
  /** New plan ID (optional, defaults to previous plan) */
  planId?: string;
  /** Payment method */
  paymentMethod?: PaymentMethod;
}

/**
 * Reactivate subscription response
 */
export interface ReactivateSubscriptionResponse {
  /** Reactivated subscription */
  subscription: SubscriptionWithRelations;
  /** Success message */
  message: string;
}

/**
 * Plan summary for listings
 */
export interface PlanSummary {
  /** Plan ID */
  id: string;
  /** Plan name */
  name: string;
  /** Display name */
  displayName: string;
  /** Monthly price */
  monthlyPrice: number;
  /** Annual price */
  annualPrice: number;
  /** Currency */
  currency: string;
  /** Sort order */
  sortOrder: number;
  /** Is popular/recommended */
  isPopular?: boolean;
}

/**
 * Subscription summary for listings
 */
export interface SubscriptionSummary {
  /** Subscription ID */
  id: string;
  /** Organization ID */
  organizationId: string;
  /** Organization name */
  organizationName?: string;
  /** Plan name */
  planName: string;
  /** Status */
  status: SubscriptionStatus;
  /** Current period end */
  currentPeriodEnd: Date;
  /** Monthly price */
  monthlyPrice: number;
  /** Created date */
  createdAt: Date;
}

// -----------------------------------------------------------------------------
// Query/Filter Types
// -----------------------------------------------------------------------------

/**
 * Subscription list query filters
 */
export interface SubscriptionListFilters {
  /** Filter by status */
  status?: SubscriptionStatus;
  /** Filter by plan ID */
  planId?: string;
  /** Filter by organization ID */
  organizationId?: string;
  /** Filter by expiring soon (within days) */
  expiringSoon?: number;
  /** Filter by trial status */
  inTrial?: boolean;
  /** Search by organization name */
  search?: string;
}

/**
 * Subscription list query params
 */
export interface SubscriptionListParams extends SubscriptionListFilters {
  /** Page number (1-indexed) */
  page?: number;
  /** Items per page */
  perPage?: number;
  /** Sort field */
  sortBy?: 'createdAt' | 'currentPeriodEnd' | 'status';
  /** Sort direction */
  sortOrder?: 'asc' | 'desc';
}

/**
 * Invoice list query filters
 */
export interface InvoiceListFilters {
  /** Filter by status */
  status?: InvoiceStatus;
  /** Filter by subscription ID */
  subscriptionId?: string;
  /** Filter by organization ID */
  organizationId?: string;
  /** Filter by date range */
  startDate?: Date;
  endDate?: Date;
}

/**
 * Invoice list query params
 */
export interface InvoiceListParams extends InvoiceListFilters {
  /** Page number (1-indexed) */
  page?: number;
  /** Items per page */
  perPage?: number;
  /** Sort field */
  sortBy?: 'createdAt' | 'dueDate' | 'totalAmount' | 'status';
  /** Sort direction */
  sortOrder?: 'asc' | 'desc';
}

// -----------------------------------------------------------------------------
// Event Payload Types
// -----------------------------------------------------------------------------

/**
 * Subscription created event payload
 */
export interface SubscriptionCreatedEvent {
  /** Subscription ID */
  subscriptionId: string;
  /** Organization ID */
  organizationId: string;
  /** Plan ID */
  planId: string;
  /** Plan name */
  planName: string;
  /** Is trial */
  isTrial: boolean;
  /** Event timestamp */
  timestamp: string;
}

/**
 * Subscription cancelled event payload
 */
export interface SubscriptionCancelledEvent {
  /** Subscription ID */
  subscriptionId: string;
  /** Organization ID */
  organizationId: string;
  /** Cancellation reason */
  reason?: string;
  /** Access ends at */
  accessEndsAt: string;
  /** Event timestamp */
  timestamp: string;
}

/**
 * Plan changed event payload
 */
export interface PlanChangedEvent {
  /** Subscription ID */
  subscriptionId: string;
  /** Organization ID */
  organizationId: string;
  /** Previous plan ID */
  previousPlanId: string;
  /** New plan ID */
  newPlanId: string;
  /** Was upgrade */
  isUpgrade: boolean;
  /** Changed by user ID */
  changedBy?: string;
  /** Event timestamp */
  timestamp: string;
}

/**
 * Trial started event payload
 */
export interface TrialStartedEvent {
  /** Subscription ID */
  subscriptionId: string;
  /** Organization ID */
  organizationId: string;
  /** Plan ID */
  planId: string;
  /** Trial end date */
  trialEndsAt: string;
  /** Event timestamp */
  timestamp: string;
}

/**
 * Trial ended event payload
 */
export interface TrialEndedEvent {
  /** Subscription ID */
  subscriptionId: string;
  /** Organization ID */
  organizationId: string;
  /** Converted to paid */
  converted: boolean;
  /** Event timestamp */
  timestamp: string;
}

/**
 * Invoice paid event payload
 */
export interface InvoicePaidEvent {
  /** Invoice ID */
  invoiceId: string;
  /** Subscription ID */
  subscriptionId: string;
  /** Organization ID */
  organizationId: string;
  /** Amount paid */
  amount: number;
  /** Currency */
  currency: string;
  /** Payment method */
  paymentMethod: PaymentMethod;
  /** Event timestamp */
  timestamp: string;
}

// -----------------------------------------------------------------------------
// Hook Context Types
// -----------------------------------------------------------------------------

/**
 * Before create subscription hook context
 */
export interface BeforeCreateContext {
  /** Create request data */
  data: CreateSubscriptionRequest;
  /** User creating the subscription */
  userId?: string;
}

/**
 * After create subscription hook context
 */
export interface AfterCreateContext {
  /** Created subscription */
  subscription: Subscription;
  /** User who created */
  userId?: string;
}

/**
 * Before plan change hook context
 */
export interface BeforePlanChangeContext {
  /** Subscription ID */
  subscriptionId: string;
  /** Current plan ID */
  currentPlanId: string;
  /** New plan ID */
  newPlanId: string;
  /** User making the change */
  userId?: string;
}

/**
 * After plan change hook context
 */
export interface AfterPlanChangeContext {
  /** Updated subscription */
  subscription: Subscription;
  /** Previous plan */
  previousPlan: Plan;
  /** New plan */
  newPlan: Plan;
  /** User who made the change */
  userId?: string;
}

// -----------------------------------------------------------------------------
// Module Settings Types
// -----------------------------------------------------------------------------

/**
 * Subscription module settings
 */
export interface SubscriptionModuleSettings {
  /** Trial period in days */
  trialDays: number;
  /** Grace period for failed payments in days */
  gracePeriodDays: number;
  /** Default currency */
  defaultCurrency: string;
  /** Auto-renew subscriptions */
  autoRenew: boolean;
  /** Send renewal reminders */
  sendRenewalReminders: boolean;
  /** Days before expiry to send reminders */
  reminderDays: number[];
}

// -----------------------------------------------------------------------------
// Type Guards
// -----------------------------------------------------------------------------

/**
 * Type guard to check if an object is a valid Plan
 */
export function isPlan(obj: unknown): obj is Plan {
  return (
    typeof obj === 'object' &&
    obj !== null &&
    'id' in obj &&
    'name' in obj &&
    'monthlyPrice' in obj &&
    'isActive' in obj
  );
}

/**
 * Type guard to check if an object is a valid Subscription
 */
export function isSubscription(obj: unknown): obj is Subscription {
  return (
    typeof obj === 'object' &&
    obj !== null &&
    'id' in obj &&
    'organizationId' in obj &&
    'planId' in obj &&
    'status' in obj
  );
}

/**
 * Type guard to check if a string is a valid PlanTier
 */
export function isPlanTier(value: unknown): value is PlanTier {
  return (
    typeof value === 'string' &&
    ['free', 'starter', 'professional', 'business', 'enterprise'].includes(value)
  );
}

/**
 * Helper to get tier order (for comparison)
 */
export function getTierOrder(tier: PlanTier): number {
  const order: Record<PlanTier, number> = {
    free: 0,
    starter: 1,
    professional: 2,
    business: 3,
    enterprise: 4,
  };
  return order[tier] ?? 0;
}

/**
 * Helper to check if one tier is higher than another
 */
export function isTierHigher(tier1: PlanTier, tier2: PlanTier): boolean {
  return getTierOrder(tier1) > getTierOrder(tier2);
}
